from typing import List

class Solution:
    def solveNQueens(self, n: int) -> bool:
        def is_safe(board: List[List[str]], row: int) -> bool:
            for col in range(n):
                if board[row][col] == 'Q':
                    return False
            return True

        def solve_n_queens_helper(board: List[List[str]], row: int) -> bool:
            if row == n:
                return True
            for col in range(n):
                if is_safe(board, row):
                    board[row][col] = 'Q'
                    if solve_n_queens_helper(board, row + 1):
                        return True
                    board[row][col] = '.'
            return False

        board = [['.'] * n for _ in range(n)]
        return solve_n_queens_helper(board, 0)

if __name__ == '__main__':
    n = int(input())
    solution = Solution()
    result = solution.solveNQueens(n)
    print('true' if result else 'false')

