#include <bits/stdc++.h>

using namespace std;
class Solution {
public:
    bool solveNQueens(int n) {
        bool board[n][n];
        for (int i = 0; i < n; i++) {
            for (int j = 0; j < n; j++) {
                board[i][j] = false;
            }
        }
        bool isSafe(int row, int col) {
            for (int i = 0; i < n; i++) {
                if (board[row][i]) return false;
                if (board[i][col]) return false;
                if (row - i == col - i) return false;
                if (row - i == n - 1 - col - i) return false;
            }
            return true;
        }

        bool solve_n_queens_helper(int row) {
            if (row == n) return true;
            for (int col = 0; col < n; col++) {
                if (isSafe(row, col)) {
                    board[row][col] = true;
                    if (solve_n_queens_helper(row + 1)) return true;
                    board[row][col] = false;
                }
            }
            return false;
        }

        return solve_n_queens_helper(0);
    }
};

int main() {
    int n;
    cin >> n;
    Solution solution;
    bool result = solution.solveNQueens(n);
    cout << (result ? 'true' : 'false') << endl;
    return 0;
}
